import React from 'react'
import Link from 'gatsby-link'
const Menu = () => (
    <div style={{paddingTop: "5px", width:"30%", right: "0px", position: "absolute",}}>
    <ul style={{ listStyle: 'none', display: 'flex', justifyContent: 'space-evenly', color: "#F00"}}>
      <li><Link to="/about">Home</Link></li>
      <li><Link to="/about">About</Link></li>
      <li><Link to="/projects">Projects</Link></li>
      <li><Link to="/career">My Career</Link></li>
    </ul>
    </div>
)


export default Menu;



