import React from 'react'
import { Navbar, Nav, NavItem, NavDropdown, MenuItem } from 'react-bootstrap';
import { LinkContainer } from "react-router-bootstrap";
import Link from 'gatsby-link'
const MyHeader = () => (
  <Navbar inverse collapseOnSelect>
    <Navbar.Header>
      <Navbar.Brand>
        Neel Patel
      </Navbar.Brand>
      <Navbar.Toggle />
    </Navbar.Header>
    <Navbar.Collapse>
      <Nav>
        <NavDropdown eventKey={3} title="Contact Me!" id="basic-nav-dropdown">
          <MenuItem eventKey={3.1} href="https://github.com/neelpatel14">Github</MenuItem>
          <MenuItem eventKey={3.2} href="https://www.linkedin.com/in/npatel14">LinkedIn</MenuItem>
          <MenuItem divider />
          <MenuItem eventKey={3.3}href="mailto:patel.neel4550@gmail.com?Subject=Work%20Offer">Email</MenuItem>
        </NavDropdown>
      </Nav>
      <Nav pullRight>
        <LinkContainer to="/about" style={{color:"white"}}>
          <NavItem eventKey={1}>
            Projects
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/projects" style={{color:"white"}}>
          <NavItem eventKey={2}>
            Projects
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/career" style={{color:"white"}}>
          <NavItem eventKey={3}>
            Projects
          </NavItem>
        </LinkContainer>
      </Nav>
    </Navbar.Collapse>
  </Navbar>
)

export default MyHeader;



